public int active()
{
    int ret = next active();
    if(ETGACFParameters::find().EnableMandatoryFields == NoYes::Yes)
    {
        FormDataSource      purchAgreement_ds         = any2Object(this) as FormDataSource;
        purchAgreement_ds.object(fieldNum(InventDim, configId)).mandatory(true);
        purchAgreement_ds.object(fieldNum(InventDim, InventSizeId)).mandatory(true);
        purchAgreement_ds.object(fieldNum(InventDim, InventColorId)).mandatory(true);
        purchAgreement_ds.object(fieldNum(InventDim, InventStyleId)).mandatory(true);
        purchAgreement_ds.object(fieldNum(InventDim, InventSiteId)).mandatory(true);
        purchAgreement_ds.object(fieldNum(InventDim, InventLocationId)).mandatory(true);
    }
    return ret;
}

public boolean validateWrite()
{
    boolean ret = next validateWrite();

    if (ETGACFParameters::find().EnableMandatoryFields == NoYes::Yes)
    {
        InventDim inventDim = (this as FormDataSource).cursor();
        FormDataSource      invDim         = any2Object(this) as FormDataSource;
        formRun             formRun                         = invDim.formRun();

        ret = ETGPurchAgreementMandatoryValidation::validateFormLines(this.formRun());
    }

    return true;
}
